INSERT INTO RAG_Chunks (id, source_id, chunk_text, chunk_index, embedding_key)
VALUES ('chk_ch05_0144', 'src_ch05', 'Perpetua & Felicitas in Carthage | Perpetua, Felicitas, Saturus | | **c. 155â€“225 AD** | Life and work of Tertullian (coined Latin Trinity terms) | Tertullian | | **c. 200â€“258 AD** | Life and work of Cyprian of Carthage | Cyprian | | **256 AD** | Council of Carthage (baptismal controversy) | Cyprian | | **258 AD** | Martyrdom of Cyprian in Carthage | Cyprian | | **303â€“305 AD** | The Great Persecution under Diocletian | Diocletian | | **c. 311â€“411 AD** | The Donatist Schism divides the', 143, NULL);
